INSERT INTO HC_MEMBER_MENU 
	(
	  MEM_SEQ
	, MEM_ID
	, MENU_ID
	, ROLE_ID
	, MENU_USE
	, REG_DT
	, REG_ID
	, MOD_DT
	, MOD_ID
	)
VALUES
	(
	  #{memSeq}
	, #{memId}
	, #{menuId}
	, #{roleId}
	, #{menuUse}
	, NOW()
	, #{regMemId}
	, NOW()
	, #{regMemId}
	) ON DUPLICATE KEY UPDATE MENU_USE = #{menuUse}, MOD_DT = NOW(), MOD_ID = #{regMemId}
